from random import randint
import random
import pandas as pd
import numpy as np

'''
Markov Chain Text Generator
This version separates the text into words not characters.
Author: Dominic Leo
'''

class Markov:
    def __init__(self):
        self.vowel_count = 0
        self.consonant_count = 0

        self.misc_char = "()-"
        self.all_words = []
        self.unique_words = {}
        self.word_map = {
            "type": list(self.unique_words.keys())
        }
        self.output_text = []
        self.df = pd.DataFrame(self.word_map)
    
    # building vocabulary and following word probability dataframe
    def train_model(self, _list):
        self.text_sample = _list
        self.separate_into_words(self.text_sample) # separates the words in to a list
        self.build_map() # creates a dataframe of the occurrence of every word to follow every word
        self.pairs_count(list(self.unique_words.keys()))

    def separate_into_words(self, sample_text):
        self.all_words = sample_text.split(" ")
        print(f"Sample text is {len(self.all_words)} words long")
        for index, word in enumerate(self.all_words):            
            # remove misc characters from the word
            for char in word:
                if char in self.misc_char:
                    word = word.replace(char, "")

            if word not in self.unique_words.keys():
                self.unique_words[word] = 1
                
            else:
                self.unique_words[word] += 1
        
    def build_map(self):
        total_unique_words = list(self.unique_words.keys())
        self.df = pd.DataFrame(0, index=total_unique_words, columns=total_unique_words)

    def pairs_count(self, _list):
        # calculates the number of times each word in the dataframe occurs after a given word, for all the words
        col = 1
        row = 0

        for index1, char1 in enumerate(_list):
            if index1 < len(_list) - 1:
                row = list(self.unique_words.keys()).index(char1) # finds the present word
                col = list(self.unique_words.keys()).index(_list[index1 + 1]) # finds the next word
                
                self.df.iloc[row, col] += 1
        
        # print(f"total char: {self.df.select_dtypes(include="number").sum().sum()}")


    # generate text
    def generate_txt(self, duration):
        # Generates the first word based on the proportions of capitalised words in the sample text
        self.first_char()
        while len(self.output_text) < duration:
            self.output_text.append(self.next_char()) # generates and appends subsequent words based on the probability of the word_map

        text = ' '.join(self.output_text)
        text += '.'
        print(f"\nGENERATED TEXT:")
        print(text)

    def first_char(self):
        # find all capitalised words and choose based on the probability that they occur in the sample text
        first_words = [word for word in list(self.unique_words.keys()) if word and word[0].isupper()]
        weights = [self.unique_words[word] for word in first_words]

        self.output_text.append(random.choices(first_words, weights, k=1)[0])
        
    def next_char(self):
        # write the subsequent letters in the text
        char = self.output_text[-1] # check the last word in the output text

        # obtain the probability of potential following words for the current word
        probabilities = self.df.loc[char].astype(float).to_numpy() # convert to numpy array to calculate probabilities
        total = probabilities.sum()
        if total == 0:
            probabilities = np.ones_like(probabilities) / len(probabilities) # prevent divide by 1 error. If word has no following words in the sample a uniform distribution is applied
        else:
            probabilities = [x / total for x in probabilities]

        next_word = random.choices(list(self.unique_words.keys()), probabilities, k=1)[0]
        return next_word

text_genertor = Markov()

